1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	};
10	
11	interface QuoteStep {
12	  op: "quote";
13	  items: { type: string }[];
14	}
15	
16	interface Scenario {
17	  customer: { yearsWithMHPCO: number };
18	  steps: QuoteStep[];
19	}
20	
21	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
22	const COMPONENT_BASE = 25;
23	const BLOCK_SIZE = 3;
24	const BLOCK_BASE = 60;
25	
26	const componentBase = (count: number): number =>
27	  count === BLOCK_SIZE ? BLOCK_BASE : count * COMPONENT_BASE;
28	
29	const baseForType = (type: string, count: number): number =>
30	  COMPONENT_TYPES.has(type)
31	    ? componentBase(count)
32	    : (BASE_PREMIUMS[type] ?? 0) * count;
33	
34	const countByType = (items: { type: string }[]): Map<string, number> =>
35	  items.reduce(
36	    (counts, item) =>
37	      counts.set(item.type, (counts.get(item.type) ?? 0) + 1),
38	    new Map<string, number>(),
39	  );
40	
41	const baseForItems = (items: { type: string }[]): number => {
42	  let total = 0;
43	  for (const [type, count] of countByType(items)) {
44	    total += baseForType(type, count);
45	  }
46	  return total;
47	};
48	
49	const priceQuote = (items: { type: string }[]): { premium: number } => {
50	  const policyBase = baseForItems(items);
51	  const firstInsuranceSurcharge = policyBase * FIRST_INSURANCE_RATE;
52	  const premium = Math.ceil(
53	    policyBase + firstInsuranceSurcharge + PROCESSING_FEE,
54	  );
55	  return { premium };
56	};
57	
58	export const runScenario = (scenario: Scenario): { results: unknown[] } => {
59	  const results = scenario.steps.map((step) => priceQuote(step.items));
60	  return { results };
61	};
